#include <bits/stdc++.h>
using namespace std;

int main() {
	int n,k;
	vector<int> q(n);
	cin>>n>>k;
	for(int i=0; i<n; i++) {
		cin>>q[i];
	}
	sort(q.begin(),q.end());
	q.erase(unique(q.begin(), q.end()), q.end()); 
	if(k>q.size()){
		cout<<"NO RESULT";
	}else{
		cout<<q[k-1];
	}
	return 0;
}
